INSERT INTO oem_wheels (id, wheel_title, part_numbers, diameter_ref, width_ref, bolt_pattern_ref, brand_ref, vehicle_ref, center_bore_ref, wheel_offset, weight, notes, color, bad_pic_url, production_ready)
VALUES (
  'jaguar-sunda-7016-wheels',
  'Jaguar Sunda #7016 Wheels',
  'Front: C2D31789, Rear: C2D31790. Genuine Jaguar OEM parts with full manufacturer warranty. Sold individually, set requires both front and rear part numbers.',
  '[{"value":19,"unit":"inch","raw":"19 inch"}]',
  '[{"value":9,"unit":"J","raw":"9.0J"},{"value":10,"unit":"J","raw":"10.0J"}]',
  '[{"value":"5x108mm PCD (5-bolt pattern with 108mm bolt circle diameter, standard for modern Jaguar vehicles)"}]',
  '[{"value":"jaguar"}]',
  '[{"value":"Jaguar - X351: XJ (2010-2022)"},{"value":"Jaguar - X351: XJR575 (2017-2019)"}]',
  '[{"value":"63.4mm (standard Jaguar hub bore diameter for precise centering and vibration-free operation)"}]',
  'Front: ET49, Rear: ET46 (optimized offset for XJ chassis geometry and performance)',
  '',
  'The Sunda wheel design is inspired by Jaguar''s motorsport heritage, featuring an innovative and robust spoke pattern that combines sophistication with practicality. Manufactured in the UK by Jaguar to exacting OEM specifications for perfect fitment and performance integration. These wheels were engineered specifically for the X351 generation XJ series, including the high-performance XJR575 variant. The staggered width setup (9J front, 10J rear) provides optimal weight distribution and handling characteristics. Standard tire fitment includes 245/45R19 front and 275/40R19 rear. Production period spans approximately 2016-2019 model years. Backed by Jaguar''s 2-year warranty when purchased as genuine OEM parts.',
  'Sparkle Silver (standard factory finish), also known as Sunda Silver Sparkle. Premium alloy construction with durable clear coat finish designed for superior corrosion resistance.',
  '![[Jaguar_Sunda_7016_Wheels.jpg]]',
  true
) ON CONFLICT (id) DO UPDATE SET
