VALUES (
  'bmw-style-59',
  'BMW Style 59',
  'Front: 8J x 18 ET20, Rear: 9J x 18 ET22 (E52 Z8 Specific)',
  '[{"value":18,"unit":"inch","raw":"18 inch"}]',
  '[{"value":8,"unit":"J","raw":"8.0J"},{"value":9,"unit":"J","raw":"9.0J"}]',
