VALUES (
  'bmw-style-87',
  'BMW Style 87 ',
  '36116753516, 36116753517',
  '[{"value":20,"unit":"inch","raw":"20 inch"}]',
  '[{"value":9.5,"unit":"J","raw":"9.5J"},{"value":10.5,"unit":"J","raw":"10.5J"}]',
